const AI_LIMIT_MAX = 10           // 10x per jam per user
const AI_LIMIT_WINDOW = 60 * 60 * 1000  // 1 jam dalam ms

// Cek & pakai 1 slot limit .ai untuk senderNumber
// Return: { ok: true } atau { ok: false, tunggu: menit, sisa: 0 }
function checkAiLimit(num) {
    if (!_aiLimitData[num]) _aiLimitData[num] = { times: [], bonus: 0, unlimited: false }
    const d = _aiLimitData[num]
    if (d.unlimited) return { ok: true, unlimited: true }
    const now = Date.now()
    d.times = (d.times || []).filter(t => now - t < AI_LIMIT_WINDOW)
    const maxAllowed = AI_LIMIT_MAX + (d.bonus || 0)
    if (d.times.length >= maxAllowed) {
        const tunggu = Math.ceil((AI_LIMIT_WINDOW - (now - d.times[0])) / 60000)
        return { ok: false, tunggu, sisa: 0 }
    }
    d.times.push(now)
    _saveAiLimit()
    return { ok: true, sisa: maxAllowed - d.times.length }
}

// Cek sisa limit tanpa pakai slot
function getAiLimitInfo(num) {
    if (!_aiLimitData[num]) _aiLimitData[num] = { times: [], bonus: 0, unlimited: false }
    const d = _aiLimitData[num]
    if (d.unlimited) return { unlimited: true }
    const now = Date.now()
    d.times = (d.times || []).filter(t => now - t < AI_LIMIT_WINDOW)
    const maxAllowed = AI_LIMIT_MAX + (d.bonus || 0)
    const sisa = maxAllowed - d.times.length
    let tunggu = 0
    if (d.times.length > 0) tunggu = Math.ceil((AI_LIMIT_WINDOW - (now - d.times[0])) / 60000)
    return { sisa: Math.max(0, sisa), max: maxAllowed, tunggu, habis: sisa <= 0 }
}

// Tambah bonus limit ke user
function addAiBonus(num, jumlah) {
    if (!_aiLimitData[num]) _aiLimitData[num] = { times: [], bonus: 0, unlimited: false }
    _aiLimitData[num].bonus = (_aiLimitData[num].bonus || 0) + jumlah
    _saveAiLimit()
}

// Set unlimited AI limit
function setAiUnlimited(num, val) {
    if (!_aiLimitData[num]) _aiLimitData[num] = { times: [], bonus: 0, unlimited: false }
    _aiLimitData[num].unlimited = val
    _saveAiLimit()
}

// Batalkan unlimited / hapus bonus
function resetAiLimit(num) {
    if (!_aiLimitData[num]) _aiLimitData[num] = { times: [], bonus: 0, unlimited: false }
    _aiLimitData[num].unlimited = false
    _aiLimitData[num].bonus = 0
    _saveAiLimit()
}
