                if (!kota) return await sendWithTyping(from, { text: '‚öÝÔ∏è Format: .kiblat [kota]' }, { quoted: msg })
                await reactWait(from, msg.key)
                try {
                    const geo = await axios.get(`https://api.aladhan.com/v1/timingsByCity?city=${encodeURIComponent(kota)}&country=Indonesia&method=11`, { timeout: 10000 })
                    const loc = geo.data.data.meta
                    const lat = parseFloat(loc.latitude); const lng = parseFloat(loc.longitude)
                    const kaLat = 21.4225; const kaLng = 39.8262
                    const dLng = (kaLng - lng) * Math.PI / 180
                    const lat1 = lat * Math.PI / 180; const lat2 = kaLat * Math.PI / 180
                    const y = Math.sin(dLng) * Math.cos(lat2)
                    const x = Math.cos(lat1) * Math.sin(lat2) - Math.sin(lat1) * Math.cos(lat2) * Math.cos(dLng)
                    let bearing = (Math.atan2(y, x) * 180 / Math.PI + 360) % 360
                    const dirs = ['Utara','Timur Laut','Timur','Tenggara','Selatan','Barat Daya','Barat','Barat Laut']
                    const dir = dirs[Math.round(bearing / 45) % 8]
                    const dist = Math.round(6371 * Math.acos(Math.sin(lat1)*Math.sin(lat2)+Math.cos(lat1)*Math.cos(lat2)*Math.cos(dLng*Math.PI/180)))
                    let t = `üïã *ARAH KIBLAT ${kota.toUpperCase()}*\n‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ\nüß≠ *Arah:* ${Math.round(bearing)}¬∞ (${dir})\nüìè *Jarak ke Ka'bah:* ${dist.toLocaleString()} km\n\nüí° *Panduan:* Hadap ke arah ${dir}, sekitar ${Math.round(bearing)}¬∞ dari Utara.`
                    await sendWithTyping(from, { text: t }, { quoted: msg }); await reactDone(from, msg.key)
                } catch(e) { await sendWithTyping(from, { text: `‚ùå Gagal hitung kiblat untuk *${kota}*.` }, { quoted: msg }); await reactDone(from, msg.key) }
