                    await sendWithTyping(from, { image: fs.readFileSync(op), caption: `üé® *COLORIZATION COMPLETE!*\n‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ\nüì∏ Foto berhasil diwarnai!\n‚ú® Warna hangat ditambahkan otomatis\nüé≠ Kontras & saturasi dioptimalkan\n\n_Seperti foto berwarna asli!_` }, { quoted: msg })
