                if (!isImgAn) return await sendWithTyping(from, { text: '‚öÝÔ∏è Reply foto dulu lalu ketik /animate [efek]\nEfek: zoom, pan, rotate\nContoh: (reply foto) ‚Üí /animate zoom' }, { quoted: msg })
                const efekAn = fullText.split(' ')[1]?.toLowerCase() || 'zoom'
