                    let filterAn = ''
                    if (efekAn === 'zoom') filterAn = "zoompan=z='min(zoom+0.0015,1.5)':x='iw/2-(iw/zoom/2)':y='ih/2-(ih/zoom/2)':d=125:s=640x480"
                    else if (efekAn === 'pan') filterAn = "zoompan=z='1.3':x='if(lte(on,1),0,x+2)':y='ih/2-(ih/zoom/2)':d=100:s=640x480"
                    else if (efekAn === 'rotate') filterAn = "zoompan=z='1.3':x='iw/2-(iw/zoom/2)':y='ih/2-(ih/zoom/2)':d=100:s=640x480,rotate=angle='t*0.03':fillcolor=black@0:c=black"
                    else filterAn = "zoompan=z='min(zoom+0.0015,1.5)':x='iw/2-(iw/zoom/2)':y='ih/2-(ih/zoom/2)':d=125:s=640x480"
                    await execPromise(`ffmpeg -loop 1 -i ${ip} -vf "${filterAn}" -t 4 -pix_fmt yuv420p -c:v libx264 -preset fast -crf 23 ${op}`)
                    const outBuf = fs.readFileSync(op)
                    if (outBuf.length/(1024*1024) > 60) { try{fs.unlinkSync(ip);fs.unlinkSync(op)}catch(e){}; return await sendWithTyping(from, { text: '‚ùå Hasil terlalu besar.' }, { quoted: msg }) }
                    await sendWithTyping(from, { video: outBuf, caption: `üé¨ *ANIMATE COMPLETE!*\n‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ\n‚ú® Efek: ${efekAn}\n‚è±Ô∏è Durasi: 4 detik\n\n_Foto jadi hidup!_`, mimetype: 'video/mp4' }, { quoted: msg })
