                    await execPromise(`ffmpeg -i ${ip} -vf "nlmeans=1.0:7:5:3,unsharp=5:5:1.5:5:5:0.5,eq=contrast=1.1:saturation=1.1:brightness=0.02,scale='min(1920,iw)':'min(1080,ih)':force_original_aspect_ratio=decrease:flags=lanczos" -q:v 1 -compression_level 0 ${op}`)
                    await sendWithTyping(from, { image: fs.readFileSync(op), caption: `üï∞Ô∏è *REMASTER COMPLETE!*\n‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ‚îÅ\nüîß *Perbaikan yang dilakukan:*\n   ‚úÖ Noise reduction (NL-Means)\n   ‚úÖ Sharpening enhancement\n   ‚úÖ Contrast & color correction\n   ‚úÖ Upscale ke resolusi HD\n\n_Seperti baru dipotret kemarin!_` }, { quoted: msg })
