                    const ip = `./gif_in_${Date.now()}.mp4`; const op = `./gif_out_${Date.now()}.gif`; fs.writeFileSync(ip, bd)
                    await execPromise(`ffmpeg -i ${ip} -t ${durGif} -vf "fps=12,scale=320:-1:flags=lanczos,split[s0][s1];[s0]palettegen[p];[s1][p]paletteuse" -loop 0 ${op}`)
                    const outBuf = fs.readFileSync(op)
